def lcs_len(a, b):
    # dynamic programming O(n*m) small strings; fine
    n, m = len(a), len(b)
    dp = [0]*(m+1)
    for i, ca in enumerate(a, 1):
        prev = 0
        for j, cb in enumerate(b, 1):
            temp = dp[j]
            if ca == cb:
                dp[j] = prev + 1
            else:
                dp[j] = dp[j] if dp[j] >= dp[j-1] else dp[j-1]
            prev = temp
    return dp[m]

def sim_lcs(a, b):
    a2, b2 = normalize_ar2(a), normalize_ar2(b)
    L = lcs_len(a2, b2)
    denom = max(len(a2), len(b2))
    if denom == 0:
        return 0.0
    return L/denom

